"use client";

import { useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import styles from "./Sidebar.module.scss";

// ─── Icons (inline SVG to avoid any icon-lib dependency) ──
const VaultixLogo = () => (
  <svg width="44" height="44" viewBox="0 0 44 44" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="22" cy="22" r="21" stroke="#40C4D3" strokeWidth="1.5" />
    <path d="M22 8 C14 14 10 20 22 22 C34 20 30 14 22 8Z" fill="#10B981" opacity="0.8" />
    <path d="M22 36 C14 30 10 24 22 22 C34 24 30 30 22 36Z" fill="#40C4D3" opacity="0.6" />
    <circle cx="22" cy="22" r="3" fill="#E9C176" />
  </svg>
);

const IconDashboard = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <rect x="1" y="1" width="6" height="6" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
    <rect x="11" y="1" width="6" height="6" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
    <rect x="1" y="11" width="6" height="6" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
    <rect x="11" y="11" width="6" height="6" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
  </svg>
);

const IconVault = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <rect x="2" y="3" width="14" height="12" rx="2" stroke="currentColor" strokeWidth="1.5" />
    <circle cx="9" cy="9" r="2.5" stroke="currentColor" strokeWidth="1.5" />
    <path d="M9 6.5V4M9 14v-2.5M11.5 9H14M4 9h2.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

const IconBeneficiaries = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <circle cx="7" cy="6" r="3" stroke="currentColor" strokeWidth="1.5" />
    <path d="M1 16c0-3.314 2.686-5 6-5s6 1.686 6 5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    <path d="M13 8a3 3 0 0 0 0-6M17 16c0-2.761-1.5-4.5-4-5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

const IconTrigger = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <path d="M9 1v4M9 13v4M1 9h4M13 9h4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    <circle cx="9" cy="9" r="3" stroke="currentColor" strokeWidth="1.5" />
  </svg>
);

const IconActivity = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <path d="M1 9h3l2.5-6L10 14l2.5-5H17" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const IconSubscription = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <rect x="1" y="4" width="16" height="11" rx="2" stroke="currentColor" strokeWidth="1.5" />
    <path d="M1 8h16" stroke="currentColor" strokeWidth="1.5" />
    <path d="M5 12h3M13 12h1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

const IconSettings = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
    <circle cx="9" cy="9" r="2.5" stroke="currentColor" strokeWidth="1.5" />
    <path d="M9 1v2M9 15v2M1 9h2M15 9h2M3.22 3.22l1.42 1.42M13.36 13.36l1.42 1.42M14.78 3.22l-1.42 1.42M4.64 13.36l-1.42 1.42" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

const IconChevron = ({ open }) => (
  <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ transform: open ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.25s ease" }}>
    <path d="M3 5l4 4 4-4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const IconLock = () => (
  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
    <rect x="2" y="7" width="12" height="8" rx="2" stroke="currentColor" strokeWidth="1.5" />
    <path d="M5 7V5a3 3 0 0 1 6 0v2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    <circle cx="8" cy="11" r="1" fill="currentColor" />
  </svg>
);

// ─── Nav config ───────────────────────────────────────────
const NAV_ITEMS = [
  { label: "Dashboard", href: "/dashboard", icon: <IconDashboard /> },
  {
    label: "My Vault",
    href: "/dashboard/vault",
    icon: <IconVault />,
    children: [
      { label: "Documents", href: "/dashboard/vault/documents" },
      { label: "Passwords", href: "/dashboard/vault/passwords" },
      { label: "Accounts", href: "/dashboard/vault/accounts" },
    ],
  },
  { label: "Beneficiaries", href: "/dashboard/beneficiaries", icon: <IconBeneficiaries /> },
  { label: "Trigger Monitoring", href: "/dashboard/triggers", icon: <IconTrigger /> },
  { label: "Activity Logs", href: "/dashboard/activity", icon: <IconActivity /> },
];

const BOTTOM_NAV = [
  { label: "Subscription", href: "/dashboard/subscription", icon: <IconSubscription /> },
  { label: "Settings", href: "/dashboard/settings", icon: <IconSettings /> },
];

// ─── Component ────────────────────────────────────────────
export default function Sidebar() {
  const pathname = usePathname();
  const [openMenus, setOpenMenus] = useState({ "/dashboard/vault": false });

  const toggle = (href) =>
    setOpenMenus((prev) => ({ ...prev, [href]: !prev[href] }));

  const isActive = (href) =>
    pathname === href || (href !== "/dashboard" && pathname.startsWith(href));

  return (
    <aside className={styles.sidebar}>
      {/* Logo */}
      <div className={styles.logo}>
        <VaultixLogo />
        <span className={styles.logoText}>VAULTIX</span>
      </div>

      {/* Main nav */}
      <nav className={styles.nav}>
        {NAV_ITEMS.map((item) => (
          <div key={item.href}>
            {item.children ? (
              <>
                <button
                  className={`${styles.navItem} ${isActive(item.href) ? styles.active : ""}`}
                  onClick={() => toggle(item.href)}
                  aria-expanded={openMenus[item.href]}
                >
                  <span className={styles.navIcon}>{item.icon}</span>
                  <span className={styles.navLabel}>{item.label}</span>
                  <span className={styles.chevron}>
                    <IconChevron open={openMenus[item.href]} />
                  </span>
                </button>
                <div
                  className={styles.subMenu}
                  style={{ maxHeight: openMenus[item.href] ? "200px" : "0" }}
                >
                  {item.children.map((child) => (
                    <Link
                      key={child.href}
                      href={child.href}
                      className={`${styles.subItem} ${pathname === child.href ? styles.subActive : ""}`}
                    >
                      <span className={styles.subDot} />
                      {child.label}
                    </Link>
                  ))}
                </div>
              </>
            ) : (
              <Link
                href={item.href}
                className={`${styles.navItem} ${isActive(item.href) ? styles.active : ""}`}
              >
                <span className={styles.navIcon}>{item.icon}</span>
                <span className={styles.navLabel}>{item.label}</span>
              </Link>
            )}
          </div>
        ))}
      </nav>

      {/* Bottom nav */}
      <div className={styles.bottomNav}>
        {BOTTOM_NAV.map((item) => (
          <Link
            key={item.href}
            href={item.href}
            className={`${styles.navItem} ${isActive(item.href) ? styles.active : ""}`}
          >
            <span className={styles.navIcon}>{item.icon}</span>
            <span className={styles.navLabel}>{item.label}</span>
          </Link>
        ))}

        <button className={styles.lockBtn}>
          <IconLock />
          LOCK VAULT
        </button>
      </div>
    </aside>
  );
}
